import{_ as e,o as a,c as o,O as t}from"./chunks/framework.ed778163.js";const d=JSON.parse('{"title":"Hello，WHUCAO","description":"","frontmatter":{},"headers":[],"relativePath":"index.md","filePath":"index.md","lastUpdated":1685458384000}'),r={name:"index.md"},n=t('<h1 id="hello-whucao" tabindex="-1">Hello，WHUCAO <a class="header-anchor" href="#hello-whucao" aria-label="Permalink to &quot;Hello，WHUCAO&quot;">​</a></h1><p>这里是 WHUCAO 的官方自述文件，你可以在这里了解到 WHUCAO 的社区体系和 WHUCAO 的工作方式。</p><p>WHUCAO 全名 WHUCodingAndOpen，为 WHU 编程交流兼开源社区。</p><p>WHUCAO 交流群：728342352</p><h1 id="社区体系" tabindex="-1">社区体系 <a class="header-anchor" href="#社区体系" aria-label="Permalink to &quot;社区体系&quot;">​</a></h1><p>WHUCAO 分为上下游，上游为 WHUCAO Contributors，也称为 WHUCAO 核心贡献者，他们负责对于 WHUCAO 社区的日常维护和管理，并且<strong>负责WHUCAO资料的整理和收集，也就是说WHUCAO的独立资料完全来源于这些人</strong>。</p><p>为保证 WHUCAO 贡献积极性， WHUCAO 贡献者独立整理的资料仅仅在 WHUCAO 贡献者社区内传播，即小范围传播，在考试考完后会以无偿的形式开源为 WHUCAO <strong>独立仓库</strong>。因此，如果你需要获取及时的信息，请进入 WHUCAO 贡献者。</p><p>WHUCAO 下游为 WHUCAO 社区，社区可以自由讨论编程和开源资料等等相关内容。也为 WHUCAO 的用户社区。</p><h1 id="加入whucao贡献者" tabindex="-1">加入WHUCAO贡献者 <a class="header-anchor" href="#加入whucao贡献者" aria-label="Permalink to &quot;加入WHUCAO贡献者&quot;">​</a></h1><p>加入 WHUCAO 贡献者需要在 <a href="https://github.com/WHUCodingAndOpen/OpenCourseResources" target="_blank" rel="noreferrer">WHUCAO-OpenCourseResources</a> PR 资料并且被成功 Merge，此外，需要独立贡献某资料的一部分，如单独整理当年离散数学的1-3章节的内容，此外，WHUCAO 也会有部分的新手手册等社区任务，这也可以作为独立贡献的指标。 成为 WHUCAO 贡献者后可以享受其他 WHUCAO 贡献者贡献的资料，达到互利的目的。</p>',10),s=[n];function C(H,O,l,A,i,U){return a(),o("div",null,s)}const W=e(r,[["render",C]]);export{d as __pageData,W as default};
